--p3.3--


SELECT post_user_email
FROM comment, post
WHERE comment.post_user_email=post.user_email

select likes.user_email
from likes, post
where  likes.user_email in
       (SELECT post_user_email
        FROM comment, post
        WHERE comment.post_user_email=post.user_email
        )


SELECT user.*
FROM user
WHERE user.email= (select likes.user_email
from likes
where likes.post_user_email in (SELECT post_user_email
