WHERE comment.post_user_email=post.user_email
)
group by likes.user_email
order by count((likes.user_email)) desc
limit 1)

--p5--

SELECT count(pages_url)
FROM ads
WHERE pages_url="https://ulink.cl/beauchef"

SELECT count(clicks.user_email) as num_clicks
FROM clicks, ads
WHERE date_ad=ads_date_ad
AND ads_hour_add=hour_add AND clicks.ads_pages_url = "https://ulink.cl/beauchef"
GROUP BY date_ad, hour_add





SELECT count(num_clicks)
FROM (SELECT count(clicks.user_email) as num_clicks
FROM clicks, ads
WHERE date_ad=ads_date_ad
AND ads_hour_add=hour_add AND clicks.ads_pages_url = "https://ulink.cl/beauchef"
GROUP BY date_ad, hour_add) AS t
WHERE num_clicks >=2



--P3.5--
SELECT (SELECT count(num_clicks)
FROM (SELECT count(clicks.user_email) as num_clicks
FROM clicks, ads
WHERE date_ad=ads_date_ad
AND ads_hour_add=hour_add AND clicks.ads_pages_url = "https://ulink.cl/beauchef"
GROUP BY date_ad, hour_add) AS t
WHERE num_clicks >=2
)/(SELECT count(pages_url)
FROM ads
WHERE pages_url="https://ulink.cl/beauchef")*100


--p6----

SELECT name_page
from pages
where url =(SELECT pages_url
FROM clicks, ads
WHERE date_ad=ads_date_ad
AND ads_hour_add=hour_add
GROUP BY date_ad, hour_add,pages_url
ORDER BY count(ads.user_email) desc
limit 1)

